+            super::history::OpStatus::Success,
+            "fcp.slack",
+            "slack.post_message",
+            Some("z:work"),
+            &json!({"channel": "C999", "text": "hello"}),
+            Some(&json!({"ok": true, "ts": "111.222"})),
+            None,
+            None,
+            30,
+        )
+        .expect("success entry should append");
